SELECT enrollment_count
FROM course_offerings
WHERE offering_id = 0;

SELECT COUNT(*) AS course_count
FROM course_offerings
WHERE year = 2018;

SELECT course_id, section_number, enrollment_count
FROM course_offerings
WHERE course_id = '0' AND term_id = 0;

SELECT MAX(enrollment_count) AS max_enrollment_count
FROM course_offerings
WHERE offering_id = 1;
